{% comment %}
  Hero Content Section - Lumoria™
{% endcomment %}

<!-- Preload Playfair Display -->
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500;1,600;1,700&display=swap" rel="stylesheet">

{% style %}
  .ix-hero__content {
    position: relative;
    z-index: 2;
    padding: 32px 20px 28px;
    display: flex;
    flex-direction: column;
    gap: 20px;
    font-family: 'DM Sans', sans-serif;
    max-width: 480px;
  }

  /* ========== ENTRANCE ANIMATIONS ========== */
  @keyframes fadeInUp {
    from {
      opacity: 0;
      transform: translateY(30px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  .ix-hero__content .ix-tp {
    opacity: 0;
    animation: fadeInUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) 0.1s forwards;
  }

  .ix-hero__content .ix-hero__headline {
    opacity: 0;
    animation: fadeInUp 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.25s forwards;
  }

  .ix-hero__content .ix-hero__sub {
    opacity: 0;
    animation: fadeInUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) 0.4s forwards;
  }

  .ix-hero__content .ix-hero__cta-wrap {
    opacity: 0;
    animation: fadeInUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) 0.55s forwards;
  }

  .ix-hero__content .ix-hero__benefits-desk {
    opacity: 0;
    animation: fadeInUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) 0.7s forwards;
  }

  /* ========== TRUSTPILOT ROW ========== */
  .ix-tp {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-wrap: nowrap;
  }

  .ix-tp__stars {
    display: flex;
    gap: 2px;
  }

  .ix-tp__star {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 20px;
    height: 20px;
    background: #00B67A;
    border-radius: 2px;
  }

  .ix-tp__star svg {
    width: 12px;
    height: 12px;
  }

  .ix-tp__star svg path {
    fill: #fff;
  }

  .ix-tp__text {
    font-size: 13px;
    color: #3A3A3A;
    font-weight: 500;
    white-space: nowrap;
  }

  .ix-tp__text strong {
    font-weight: 700;
    color: #1a1a18;
  }

  .ix-tp__sep {
    color: #ccc;
    font-size: 13px;
    flex-shrink: 0;
  }

  /* ========== HEADLINE ========== */
  .ix-hero__headline {
    display: flex;
    flex-direction: column;
    gap: 6px;
    margin: 0;
  }

  .ix-accent-word {
    text-decoration: underline;
    text-decoration-color: #3B82F6;
    text-underline-offset: 4px;
    text-decoration-thickness: 2.5px;
  }

  /* ========== SUBHEADLINE ========== */
  .ix-hero__sub {
    font-size: 15px;
    line-height: 1.6;
    color: #3A3A3A;
    margin: 0;
    font-weight: 400;
  }

  .ix-hero__sub strong {
    font-weight: 700;
    color: #1a1a18;
  }

  /* ========== CTA WRAP ========== */
  .ix-hero__cta-wrap {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-top: 4px;
  }

  .ix-hero__cta {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    background: #1a1a18;
    color: #fff;
    font-size: 14px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    padding: 16px 32px;
    border-radius: 60px;
    text-decoration: none;
    transition: all 0.3s cubic-bezier(.16,1,.3,1);
    width: 100%;
    box-sizing: border-box;
    cursor: pointer;
  }

  .ix-hero__cta:hover {
    background: #333;
    transform: translateY(-1px);
  }

  .ix-hero__cta svg {
    width: 18px;
    height: 18px;
    stroke-width: 2.5;
    transition: transform 0.3s ease;
  }

  .ix-hero__cta:hover svg {
    transform: translateX(4px);
  }

  /* ========== GUARANTEE ========== */
  .ix-hero__guarantee {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    font-size: 13px;
    color: #5A5A5A;
    font-weight: 500;
  }

  .ix-hero__guarantee svg {
    width: 18px;
    height: 18px;
    color: #5A5A5A;
    flex-shrink: 0;
  }

  /* ========== DESKTOP BENEFITS ========== */
  .ix-hero__benefits-desk {
    display: none;
    flex-wrap: wrap;
    gap: 16px;
    margin-top: 8px;
  }

  .ix-hero__benefit-item {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    color: #3A3A3A;
    font-weight: 500;
  }

  .ix-hero__benefit-item svg {
    width: 16px;
    height: 16px;
    color: #00B67A;
    flex-shrink: 0;
  }

  /* ========== RESPONSIVE ========== */
  @media (min-width: 768px) {
    .ix-hero__content {
      padding: 48px 32px 40px;
      gap: 24px;
      max-width: 560px;
    }

    .ix-hero__sub {
      font-size: 16px;
    }

    .ix-hero__cta {
      width: auto;
      padding: 18px 40px;
      font-size: 15px;
    }

    .ix-hero__benefits-desk {
      display: flex;
    }
  }

  @media (min-width: 1024px) {
    .ix-hero__content {
      padding: 56px 40px 48px;
    }
  }
{% endstyle %}

<div class="ix-hero__content">
  <!-- Trustpilot -->
  <div class="ix-tp">
    <div class="ix-tp__stars" aria-label="Trustpilot 4.7 out of 5">
      <span class="ix-tp__star"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" fill="#fff"></path></svg></span>
      <span class="ix-tp__star"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" fill="#fff"></path></svg></span>
      <span class="ix-tp__star"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" fill="#fff"></path></svg></span>
      <span class="ix-tp__star"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" fill="#fff"></path></svg></span>
      <span class="ix-tp__star"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" fill="#fff"></path></svg></span>
    </div>
    <span class="ix-tp__text">Excellent <strong>4.7</strong></span>
    <span class="ix-tp__sep">|</span>
    <span class="ix-tp__text"><strong>32,300+</strong> Customers</span>
  </div>

  <!-- Headline with inline styles to force rendering -->
  <h1 class="ix-hero__headline">
    <span class="ix-hero__h1-main" style="display:block; font-family:'Playfair Display',Georgia,serif !important; font-size:clamp(30px,7.5vw,52px) !important; font-weight:700 !important; font-style:italic !important; line-height:1.1 !important; color:#1a1a18 !important; letter-spacing:-0.02em !important;">
      Flatten Your Belly, Burn Calories, <span class="ix-accent-word">Zero Effort</span>
    </span>
    <span class="ix-hero__h1-sub" style="display:block; font-family:'Playfair Display',Georgia,serif !important; font-size:clamp(20px,5vw,28px) !important; font-weight:400 !important; font-style:normal !important; line-height:1.25 !important; color:#4A4A4A !important; margin-top:6px !important;">
      Transform Your Body While Living Your Life
    </span>
  </h1>

  <!-- Subheadline -->
  <p class="ix-hero__sub">
    The only <strong>3D compression slimming vest</strong> — clinically tested to slim your silhouette by 30% and visibly reduce belly fat in just 30&nbsp;days.
  </p>

  <!-- CTA + Guarantee -->
  <div class="ix-hero__cta-wrap">
    <a href="javascript:void(0)" class="ix-hero__cta" id="hero-cta-btn">
      <span>Shop Now – Free Shipping</span>
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"></path><path d="m12 5 7 7-7 7"></path></svg>
    </a>
    <div class="ix-hero__guarantee">
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"></path><path d="m9 12 2 2 4-4"></path></svg>
      <span>90-Day Money-Back Guarantee</span>
    </div>
  </div>

  <!-- Desktop inline benefits -->
  <div class="ix-hero__benefits-desk">
    <span class="ix-hero__benefit-item">
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><path d="m9 11 3 3L22 4"></path></svg>
      Patented Technology
    </span>
    <span class="ix-hero__benefit-item">
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><path d="m9 11 3 3L22 4"></path></svg>
      Clinically Tested
    </span>
    <span class="ix-hero__benefit-item">
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><path d="m9 11 3 3L22 4"></path></svg>
      Visible Results in 30 Days
    </span>
  </div>
</div>

<script>
document.getElementById('hero-cta-btn').addEventListener('click', function(e) {
  e.preventDefault();
  var target = document.querySelector('.kaching-bundles__block-title');
  if (target) {
    var offset = 20;
    var targetPosition = target.getBoundingClientRect().top + window.pageYOffset - offset;
    window.scrollTo({
      top: targetPosition,
      behavior: 'smooth'
    });
  }
});
</script>

{% comment %}
  Micro Benefits Bar - Lumoria™
  Black bar with blue checks
{% endcomment %}
{% style %}
  .ix-hero__micro {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding: 10px 20px;
    background: #0A0A0A;
    flex-wrap: wrap;
    font-family: 'DM Sans', sans-serif;
  }
  .ix-hero__micro-item {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    font-size: 12px;
    font-weight: 500;
    color: #f0ece4;
    letter-spacing: 0.01em;
  }
  .ix-hero__micro-item svg {
    width: 14px;
    height: 14px;
    color: #3B82F6;
    flex-shrink: 0;
  }
  .ix-hero__micro-dot {
    width: 4px;
    height: 4px;
    background: #3B82F6;
    border-radius: 50%;
    flex-shrink: 0;
  }
  @media (max-width: 480px) {
    .ix-hero__micro {
      gap: 5px;
      padding: 8px 12px;
    }
    .ix-hero__micro-item {
      font-size: 10px;
      gap: 3px;
    }
    .ix-hero__micro-item svg {
      width: 12px;
      height: 12px;
    }
    .ix-hero__micro-dot {
      width: 3px;
      height: 3px;
    }
  }
{% endstyle %}

